    internal class BottomLeftRadiusTypeConverter : JsonConverter<BottomLeftRadiusType>
    {
        public override bool CanConvert(Type t) => t == typeof(BottomLeftRadiusType);

        public override BottomLeftRadiusType Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            var value = reader.GetString();
            if (value == "VARIABLE_ALIAS")
            {
                return BottomLeftRadiusType.VariableAlias;
            }
            throw new Exception("Cannot unmarshal type BottomLeftRadiusType");
        }

        public override void Write(Utf8JsonWriter writer, BottomLeftRadiusType value, JsonSerializerOptions options)
        {
            if (value == BottomLeftRadiusType.VariableAlias)
            {
                JsonSerializer.Serialize(writer, "VARIABLE_ALIAS", options);
                return;
            }
            throw new Exception("Cannot marshal type BottomLeftRadiusType");
        }

        public static readonly BottomLeftRadiusTypeConverter Singleton = new BottomLeftRadiusTypeConverter();
    }

    internal class PurpleMinMaxValueCheckConverter : JsonConverter<double>
    {
        public override bool CanConvert(Type t) => t == typeof(double);

        public override double Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            var value = reader.GetDouble();
            if (value >= 0 && value <= 1)
            {
                return value;
            }
            throw new Exception("Cannot unmarshal type double");
        }

        public override void Write(Utf8JsonWriter writer, double value, JsonSerializerOptions options)
        {
            if (value >= 0 && value <= 1)
            {
                JsonSerializer.Serialize(writer, value, options);
                return;
            }
            throw new Exception("Cannot marshal type double");
        }

        public static readonly PurpleMinMaxValueCheckConverter Singleton = new PurpleMinMaxValueCheckConverter();
    }

    internal class BlendModeConverter : JsonConverter<BlendMode>
    {
        public override bool CanConvert(Type t) => t == typeof(BlendMode);

        public override BlendMode Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            var value = reader.GetString();
            switch (value)
            {
                case "COLOR":
                    return BlendMode.Color;
                case "COLOR_BURN":
                    return BlendMode.ColorBurn;
                case "COLOR_DODGE":
                    return BlendMode.ColorDodge;
                case "DARKEN":
                    return BlendMode.Darken;
                case "DIFFERENCE":
                    return BlendMode.Difference;
                case "EXCLUSION":
                    return BlendMode.Exclusion;
                case "HARD_LIGHT":
                    return BlendMode.HardLight;
                case "HUE":
                    return BlendMode.Hue;
                case "LIGHTEN":
                    return BlendMode.Lighten;
                case "LINEAR_BURN":
                    return BlendMode.LinearBurn;
                case "LINEAR_DODGE":
                    return BlendMode.LinearDodge;
                case "LUMINOSITY":
                    return BlendMode.Luminosity;
                case "MULTIPLY":
                    return BlendMode.Multiply;
                case "NORMAL":
                    return BlendMode.Normal;
                case "OVERLAY":
                    return BlendMode.Overlay;
                case "PASS_THROUGH":
