                    var boolValue = reader.GetBoolean();
                    return new DefaultValueUnion { Bool = boolValue };
                case JsonTokenType.String:
                    var stringValue = reader.GetString();
                    return new DefaultValueUnion { String = stringValue };
            }
            throw new Exception("Cannot unmarshal type DefaultValueUnion");
