    internal class VariableValueValueConverter : JsonConverter<VariableValueValue>
    {
        public override bool CanConvert(Type t) => t == typeof(VariableValueValue);

        public override VariableValueValue Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            switch (reader.TokenType)
            {
                case JsonTokenType.Number:
                    var doubleValue = reader.GetDouble();
                    return new VariableValueValue { Double = doubleValue };
                case JsonTokenType.True:
                case JsonTokenType.False:
                    var boolValue = reader.GetBoolean();
                    return new VariableValueValue { Bool = boolValue };
                case JsonTokenType.String:
                    var stringValue = reader.GetString();
                    return new VariableValueValue { String = stringValue };
                case JsonTokenType.StartObject:
                    var objectValue = JsonSerializer.Deserialize<Rgb>(ref reader, options);
                    return new VariableValueValue { Rgb = objectValue };
            }
            throw new Exception("Cannot unmarshal type VariableValueValue");
        }

        public override void Write(Utf8JsonWriter writer, VariableValueValue value, JsonSerializerOptions options)
        {
            if (value.Double != null)
            {
                JsonSerializer.Serialize(writer, value.Double.Value, options);
                return;
            }
            if (value.Bool != null)
            {
                JsonSerializer.Serialize(writer, value.Bool.Value, options);
                return;
            }
            if (value.String != null)
            {
                JsonSerializer.Serialize(writer, value.String, options);
                return;
            }
            if (value.Rgb != null)
            {
                JsonSerializer.Serialize(writer, value.Rgb, options);
                return;
            }
            throw new Exception("Cannot marshal type VariableValueValue");
        }

        public static readonly VariableValueValueConverter Singleton = new VariableValueValueConverter();
    }

